// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertSame;

import java.util.LinkedHashMap;
import java.util.Map;

import org.eclipse.rdf4j.sail.lmdb.sketch.OmniWitnessSet.FallbackReason;
import org.junit.jupiter.api.Test;

class OmniSketchEstimatorServiceTest {

	private final OmniSketchEstimatorService service = new OmniSketchEstimatorService();

	@Test
	void dominantWitnessAndBindingUseLargestWitnessByIdentity() {
		OmniWitnessSet smaller = witnesses(Map.of(1L, 1.0d));
		OmniWitnessSet larger = witnesses(Map.of(2L, 2.0d, 3L, 1.0d));
		Map<String, OmniWitnessSet> witnesses = new LinkedHashMap<>();
		witnesses.put("small", smaller);
		witnesses.put("large", larger);

		OmniWitnessSet dominant = service.dominantWitness(witnesses);

		assertSame(larger, dominant);
		assertEquals("large", service.dominantWitnessBinding(witnesses, dominant));
	}

	@Test
	void membershipEstimatePreservesSourceCorrelation() {
		OmniWitnessSet source = witnesses(Map.of(1L, 1.0d, 2L, 1.0d, 3L, 1.0d));
		OmniWitnessSet membership = witnesses(Map.of(2L, 1.0d, 3L, 1.0d, 4L, 1.0d));

		assertEquals(60.0d, service.estimateMembershipRows(source, membership, 90.0d, value -> value), 1e-12);
		assertEquals(0.0d,
				service.estimateMembershipRows(OmniWitnessSet.empty(), membership, 90.0d, value -> value), 0.0d);
	}

	private static OmniWitnessSet witnesses(Map<Long, Double> weights) {
		return OmniWitnessSet.fromWeights(weights, 1.0d, 0.9d, FallbackReason.NONE, 0.0d);
	}
}
